152	                parse_pos++;
153	                count++;
154	            }
155	            int aidx = arr_vector(count);
156	            if (aidx < 0) { parse_err = 1; return 0; }
157	            int si = 0;
158	            while (si < count) {
159	                arr_set(aidx, si, strand_buf[si]);
160	                si++;
161	            }
162	            left = ast_vec(aidx);
163	        }
164	    } else if (ty == TOK_LPAREN) {
165	        parse_pos++;
166	        left = parse_node(0);
167	        if (parse_err) return 0;
168	        if (tok_type[parse_pos] != TOK_RPAREN) {
169	            parse_err = 1;
170	            return 0;
171	        }
172	        parse_pos++;
173	    } else if (ty == TOK_IDENT) {
174	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
175	        if (sym_idx < 0) { parse_err = 1; return 0; }
176	        left = ast_ident(sym_idx);
177	        parse_pos++;
178	    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
179	        // Reduce operator: +/ -/ */ (op followed by slash)
180	        int op = ty;
181	        parse_pos = parse_pos + 2;
182	        int operand = parse_node(0);
183	        if (parse_err) return 0;
184	        left = ast_reduce(op, operand);
185	    } else if (ty == TOK_RES) {
186	        // Monadic primitive function (e.g. iota expr)
187	        int res_id = tok_val[parse_pos];
188	        parse_pos++;
189	        int operand = parse_node(0);
190	        if (parse_err) return 0;
191	        left = ast_monad(res_id, operand);
192	    } else if (ty == TOK_MINUS) {
193	        // Monadic negate: applies to entire right expression (APL rule)
194	        parse_pos++;
195	        int operand = parse_node(0);
196	        if (parse_err) return 0;
197	        left = ast_neg(operand);
198	    } else {
199	        parse_err = 1;
200	        return 0;
201	    }
202	
203	    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --
204	
205	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
206	        int op = tok_type[parse_pos];
207	        parse_pos++;
208	        int right = parse_node(0);
209	        if (parse_err) return 0;
210	        return ast_binop(op, left, right);
211	    }
212	
213	    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
214	        int res_id = tok_val[parse_pos];
215	        parse_pos++;
216	        int right = parse_node(0);
217	        if (parse_err) return 0;
218	        return ast_dyad(res_id, left, right);
219	    }
220	
221	    return left;
222	}
