224	// Parse the token stream. Returns root node index, or -1 on error.
225	// line is needed for identifier name resolution into the symbol table.
226	int parse(char *line) {
227	    node_count = 0;
228	    parse_pos = 0;
229	    parse_err = 0;
230	    parse_line = line;
231	
232	    // Check for quad output: [] <- expr (IBM 5100 convention)
233	    if (tok_type[0] == TOK_QUAD && tok_type[1] == TOK_ASSIGN) {
234	        parse_pos = 2;
235	        int expr = parse_node(0);
236	        if (parse_err) return -1;
237	        if (tok_type[parse_pos] != TOK_EOL) return -1;
238	        int n = ast_new();
239	        node_type[n] = NODE_QOUT;
240	        node_right[n] = expr;
241	        return n;
242	    }
243	
244	    // Check for assignment: IDENT <- expr
245	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
246	        int sym_idx = sym_lookup(line, tok_val[0]);
247	        if (sym_idx < 0) { return -1; }
248	        parse_pos = 2;
249	        int expr = parse_node(0);
250	        if (parse_err) return -1;
251	        if (tok_type[parse_pos] != TOK_EOL) return -1;
252	        return ast_assign(sym_idx, expr);
253	    }
254	
255	    int root = parse_node(0);
256	
257	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
258	        parse_err = 1;
259	    }
260	
261	    if (parse_err) return -1;
262	    return root;
263	}
