1	// COR24 APL Interpreter -- Tokenizer
2	// Lexes input line into token array for the parser.
3	
4	#pragma once
5	
6	// Token types
7	#define TOK_EOL     0   // end of line
8	#define TOK_NUM     1   // integer literal (value in tok_val)
9	#define TOK_IDENT   2   // user identifier (uppercase, pos in tok_val)
10	#define TOK_PLUS    3   // +
11	#define TOK_MINUS   4   // - (parser decides monadic vs dyadic)
12	#define TOK_STAR    5   // *
13	#define TOK_SLASH   6   // /
14	#define TOK_LPAREN  7   // (
15	#define TOK_RPAREN  8   // )
16	#define TOK_ASSIGN  9   // <-
17	#define TOK_RES    10   // reserved word (ID in tok_val)
18	#define TOK_QUAD   11   // quad ([] — bare quad for I/O)
19	
20	// Reserved word IDs
21	#define RES_RHO     0
22	#define RES_IOTA    1
23	#define RES_TAKE    2
24	#define RES_DROP    3
25	#define RES_REV     4
26	#define RES_CAT     5
27	
28	#define TOK_MAX    64   // max tokens per line
29	
30	// Token storage (parallel arrays)
31	int tok_type[TOK_MAX];  // token type
32	int tok_val[TOK_MAX];   // numeric value or reserved word ID
33	int tok_pos[TOK_MAX];   // start position in source line
34	int tok_count;           // number of tokens produced
35	
36	// ---- String helpers ----
37	
38	// Compare a substring of src starting at pos against a NUL-terminated word.
39	// Returns 1 if match, 0 otherwise.
40	int str_match(char *src, int pos, char *word) {
41	    int i = 0;
42	    while (word[i]) {
43	        if (src[pos + i] != word[i]) return 0;
44	        i++;
45	    }
46	    return i;  // return length of match (0 = no match since word is non-empty)
47	}
48	
49	// Check if character is a lowercase letter (a-z)
50	int is_lower(int ch) {
51	    return ch >= 97 && ch <= 122;
52	}
53	
54	// Check if character is an uppercase letter (A-Z)
55	int is_upper(int ch) {
56	    return ch >= 65 && ch <= 90;
57	}
58	
59	// Check if character is a digit (0-9)
60	int is_digit(int ch) {
61	    return ch >= 48 && ch <= 57;
62	}
63	
64	// Check if character is alphanumeric or underscore
65	int is_alnum(int ch) {
66	    return is_lower(ch) || is_upper(ch) || is_digit(ch);
67	}
68	
69	// ---- Reserved word lookup ----
70	// Returns reserved word ID if the lowercase word starting at pos matches,
71	// or -1 if not a reserved word. Sets *end to position past the word.
72	int lookup_reserved(char *src, int pos, int *end) {
73	    int len;
74	
75	    len = str_match(src, pos, "rho");
76	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_RHO; }
77	
78	    len = str_match(src, pos, "iota");
79	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_IOTA; }
80	
81	    len = str_match(src, pos, "take");
82	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_TAKE; }
83	
84	    len = str_match(src, pos, "drop");
85	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_DROP; }
86	
