1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH
9	int eval_err;
10	
11	// Apply a binary op to two scalars
12	int eval_binop_scalar(int op, int a, int b) {
13	    if (op == TOK_PLUS)       return a + b;
14	    if (op == TOK_MINUS)      return a - b;
15	    if (op == TOK_STAR)       return a * b;
16	    if (op == TOK_SLASH) {
17	        if (b == 0) { eval_err = 1; return 0; }
18	        return a / b;
19	    }
20	    eval_err = 1;
21	    return 0;
22	}
23	
24	// Evaluate AST node, return heap index of result array.
25	// On error, sets eval_err and returns -1.
26	int eval(int n) {
27	    if (eval_err) return -1;
28	    if (n < 0 || n >= node_count) {
29	        eval_err = 1;
30	        return -1;
31	    }
32	
33	    int ty = node_type[n];
34	
35	    if (ty == NODE_NUM) {
36	        int r = arr_scalar(node_val[n]);
37	        if (r < 0) { eval_err = 1; return -1; }
38	        return r;
39	    }
40	
41	    if (ty == NODE_VEC) {
42	        return node_val[n];
43	    }
44	
45	    if (ty == NODE_IDENT) {
46	        int idx = node_val[n];
47	        if (!sym_set_flag[idx]) {
48	            eval_err = 2;
49	            return -1;
50	        }
51	        return sym_val[idx];
52	    }
53	
54	    if (ty == NODE_ASSIGN) {
55	        int idx = node_val[n];
56	        int v = eval(node_right[n]);
57	        if (eval_err) return -1;
58	        sym_val[idx] = v;
59	        sym_set_flag[idx] = 1;
60	        return v;
61	    }
62	
63	    if (ty == NODE_QOUT) {
64	        int v = eval(node_right[n]);
65	        if (eval_err) return -1;
66	        return v;
67	    }
68	
69	    if (ty == NODE_NEG) {
70	        int v = eval(node_right[n]);
71	        if (eval_err) return -1;
72	        int rk = arr_rank(v);
73	        if (rk == 0) {
74	            int r = arr_scalar(0 - arr_get(v, 0));
75	            if (r < 0) { eval_err = 1; return -1; }
76	            return r;
77	        }
78	        // Negate each element of vector
79	        int sz = arr_size(v);
80	        int r = arr_vector(sz);
81	        if (r < 0) { eval_err = 1; return -1; }
82	        int i = 0;
83	        while (i < sz) {
84	            arr_set(r, i, 0 - arr_get(v, i));
85	            i++;
86	        }
87	        return r;
88	    }
89	
90	    if (ty == NODE_MONAD) {
91	        int v = eval(node_right[n]);
92	        if (eval_err) return -1;
93	        int res_id = node_val[n];
94	
95	        if (res_id == RES_IOTA) {
96	            // iota N: generate vector 0 1 2 ... N-1
97	            if (arr_rank(v) != 0) { eval_err = 3; return -1; }
98	            int count = arr_get(v, 0);
99	            if (count < 0) { eval_err = 1; return -1; }
100	            int r = arr_vector(count);
101	            if (r < 0) { eval_err = 1; return -1; }
102	            int i = 0;
103	            while (i < count) {
104	                arr_set(r, i, i);
105	                i++;
106	            }
107	            return r;
108	        }
109	
110	        if (res_id == RES_RHO) {
111	            // rho A: return shape of A
112	            int rk = arr_rank(v);
113	            if (rk == 0) {
114	                // Scalar: shape is empty vector
115	                int r = arr_vector(0);
116	                if (r < 0) { eval_err = 1; return -1; }
117	                return r;
118	            }
119	            if (rk == 1) {
120	                // Vector: shape is 1-element vector with length
121	                int r = arr_scalar(arr_dim0(v));
122	                if (r < 0) { eval_err = 1; return -1; }
123	                return r;
124	            }
125	            if (rk == 2) {
126	                // Matrix: shape is 2-element vector (rows cols)
127	                int r = arr_vector(2);
128	                if (r < 0) { eval_err = 1; return -1; }
129	                arr_set(r, 0, arr_dim0(v));
130	                arr_set(r, 1, arr_dim1(v));
131	                return r;
132	            }
133	            eval_err = 1;
134	            return -1;
135	        }
136	
137	        // Unknown monadic function
138	        eval_err = 1;
139	        return -1;
140	    }
141	
142	    if (ty == NODE_REDUCE) {
143	        int v = eval(node_right[n]);
144	        if (eval_err) return -1;
145	        int op = node_val[n];
146	        int rk = arr_rank(v);
147	
148	        // Scalar reduce: just return the scalar
149	        if (rk == 0) {
150	            return v;
151	        }
152	
153	        // Vector reduce: right-to-left fold
154	        if (rk == 1) {
155	            int sz = arr_size(v);
156	            if (sz == 0) { eval_err = 1; return -1; }
157	            int acc = arr_get(v, sz - 1);
158	            int i = sz - 2;
159	            while (i >= 0) {
160	                acc = eval_binop_scalar(op, arr_get(v, i), acc);
161	                if (eval_err) return -1;
162	                i--;
163	            }
164	            int r = arr_scalar(acc);
165	            if (r < 0) { eval_err = 1; return -1; }
166	            return r;
167	        }
168	
169	        // Unsupported rank
170	        eval_err = 1;
171	        return -1;
172	    }
173	
174	    if (ty == NODE_DYAD) {
175	        int lv = eval(node_left[n]);
176	        if (eval_err) return -1;
177	        int rv = eval(node_right[n]);
178	        if (eval_err) return -1;
179	        int res_id = node_val[n];
180	
181	        if (res_id == RES_RHO) {
182	            // S rho A: reshape A to shape S with cyclic fill
183	            // S is scalar -> result is vector of that length
184	            // S is 2-element vector -> result is matrix
185	            int lrk = arr_rank(lv);
186	            int new_rank;
187	            int d0;
188	            int d1;
189	
190	            if (lrk == 0) {
191	                // Scalar shape -> vector
192	                new_rank = 1;
193	                d0 = arr_get(lv, 0);
194	                d1 = 0;
195	                if (d0 < 0) { eval_err = 1; return -1; }
196	            } else if (lrk == 1) {
197	                int lsz = arr_size(lv);
198	                if (lsz == 1) {
199	                    new_rank = 1;
200	                    d0 = arr_get(lv, 0);
201	                    d1 = 0;
202	                    if (d0 < 0) { eval_err = 1; return -1; }
203	                } else if (lsz == 2) {
204	                    new_rank = 2;
205	                    d0 = arr_get(lv, 0);
206	                    d1 = arr_get(lv, 1);
207	                    if (d0 < 0 || d1 < 0) { eval_err = 1; return -1; }
208	                } else {
209	                    // Only rank 1 and 2 supported
210	                    eval_err = 1;
211	                    return -1;
212	                }
213	            } else {
214	                eval_err = 1;
215	                return -1;
216	            }
217	
218	            int r = arr_new(new_rank, d0, d1);
219	            if (r < 0) { eval_err = 1; return -1; }
220	
221	            int total = arr_size(r);
222	            int src_sz = arr_size(rv);
223	            if (src_sz == 0) { eval_err = 1; return -1; }
224	
225	            int i = 0;
226	            while (i < total) {
227	                arr_set(r, i, arr_get(rv, i % src_sz));
228	                i++;
229	            }
230	            return r;
231	        }
232	
233	        if (res_id == RES_TAKE) {
234	            // N take A: take first N elements (negative N = from end)
235	            if (arr_rank(lv) != 0) { eval_err = 1; return -1; }
236	            int count = arr_get(lv, 0);
237	            int sz = arr_size(rv);
238	            int abs_n = count;
239	            if (abs_n < 0) abs_n = 0 - abs_n;
240	            if (abs_n > sz) { eval_err = 3; return -1; }
241	
242	            int r = arr_vector(abs_n);
243	            if (r < 0) { eval_err = 1; return -1; }
244	            int start = 0;
245	            if (count < 0) start = sz - abs_n;
246	            int i = 0;
247	            while (i < abs_n) {
248	                arr_set(r, i, arr_get(rv, start + i));
249	                i++;
250	            }
251	            return r;
