        // Vector reduce: right-to-left fold
        if (rk == 1) {
            int sz = arr_size(v);
            if (sz == 0) { eval_err = 1; return -1; }
            int acc = arr_get(v, sz - 1);
            int i = sz - 2;
            while (i >= 0) {
                acc = eval_binop_scalar(op, arr_get(v, i), acc);
                if (eval_err) return -1;
                i--;
            }
            int r = arr_scalar(acc);
            if (r < 0) { eval_err = 1; return -1; }
            return r;
        }

        // Unsupported rank
        eval_err = 1;
        return -1;
    }

    if (ty == NODE_DYAD) {
        int lv = eval(node_left[n]);
        if (eval_err) return -1;
        int rv = eval(node_right[n]);
        if (eval_err) return -1;
        int res_id = node_val[n];

        if (res_id == RES_RHO) {
            // S rho A: reshape A to shape S with cyclic fill
            // S is scalar -> result is vector of that length
            // S is 2-element vector -> result is matrix
            int lrk = arr_rank(lv);
            int new_rank;
            int d0;
            int d1;

            if (lrk == 0) {
                // Scalar shape -> vector
                new_rank = 1;
                d0 = arr_get(lv, 0);
                d1 = 0;
                if (d0 < 0) { eval_err = 1; return -1; }
            } else if (lrk == 1) {
                int lsz = arr_size(lv);
                if (lsz == 1) {
                    new_rank = 1;
                    d0 = arr_get(lv, 0);
                    d1 = 0;
                    if (d0 < 0) { eval_err = 1; return -1; }
                } else if (lsz == 2) {
                    new_rank = 2;
                    d0 = arr_get(lv, 0);
                    d1 = arr_get(lv, 1);
                    if (d0 < 0 || d1 < 0) { eval_err = 1; return -1; }
                } else {
                    // Only rank 1 and 2 supported
                    eval_err = 1;
                    return -1;
                }
            } else {
                eval_err = 1;
                return -1;
            }

            int r = arr_new(new_rank, d0, d1);
            if (r < 0) { eval_err = 1; return -1; }

            int total = arr_size(r);
            int src_sz = arr_size(rv);
            if (src_sz == 0) { eval_err = 1; return -1; }

            int i = 0;
            while (i < total) {
                arr_set(r, i, arr_get(rv, i % src_sz));
                i++;
            }
            return r;
        }

        if (res_id == RES_TAKE) {
            // N take A: take first N elements (negative N = from end)
            if (arr_rank(lv) != 0) { eval_err = 1; return -1; }
            int count = arr_get(lv, 0);
            int sz = arr_size(rv);
            int abs_n = count;
            if (abs_n < 0) abs_n = 0 - abs_n;
            if (abs_n > sz) { eval_err = 3; return -1; }

            int r = arr_vector(abs_n);
            if (r < 0) { eval_err = 1; return -1; }
            int start = 0;
            if (count < 0) start = sz - abs_n;
            int i = 0;
            while (i < abs_n) {
                arr_set(r, i, arr_get(rv, start + i));
                i++;
            }
            return r;
        }

        if (res_id == RES_DROP) {
            // N drop A: drop first N elements (negative N = from end)
            if (arr_rank(lv) != 0) { eval_err = 1; return -1; }
            int count = arr_get(lv, 0);
            int sz = arr_size(rv);
            int abs_n = count;
            if (abs_n < 0) abs_n = 0 - abs_n;
            if (abs_n > sz) abs_n = sz;

            int new_sz = sz - abs_n;
            int r = arr_vector(new_sz);
            if (r < 0) { eval_err = 1; return -1; }
            int start = abs_n;
            if (count < 0) start = 0;
            int i = 0;
            while (i < new_sz) {
                arr_set(r, i, arr_get(rv, start + i));
                i++;
            }
            return r;
        }

        // Unknown dyadic function
        eval_err = 1;
        return -1;
    }

    if (ty == NODE_BINOP) {
        int lv = eval(node_left[n]);
        if (eval_err) return -1;
        int rv = eval(node_right[n]);
        if (eval_err) return -1;

        int lrk = arr_rank(lv);
        int rrk = arr_rank(rv);
        int op = node_val[n];

        // Scalar op scalar
        if (lrk == 0 && rrk == 0) {
            int result = eval_binop_scalar(op, arr_get(lv, 0), arr_get(rv, 0));
            if (eval_err) return -1;
            int r = arr_scalar(result);
            if (r < 0) { eval_err = 1; return -1; }
            return r;
        }

        // Vector op vector: must match length
        if (lrk == 1 && rrk == 1) {
            int lsz = arr_size(lv);
            int rsz = arr_size(rv);
            if (lsz != rsz) { eval_err = 3; return -1; }
            int r = arr_vector(lsz);
            if (r < 0) { eval_err = 1; return -1; }
            int i = 0;
            while (i < lsz) {
                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Scalar op vector
        if (lrk == 0 && rrk == 1) {
            int la = arr_get(lv, 0);
            int rsz = arr_size(rv);
            int r = arr_vector(rsz);
            if (r < 0) { eval_err = 1; return -1; }
            int i = 0;
            while (i < rsz) {
                int val = eval_binop_scalar(op, la, arr_get(rv, i));
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Vector op scalar
        if (lrk == 1 && rrk == 0) {
            int ra = arr_get(rv, 0);
            int lsz = arr_size(lv);
            int r = arr_vector(lsz);
            if (r < 0) { eval_err = 1; return -1; }
            int i = 0;
            while (i < lsz) {
                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Unsupported rank combination
        eval_err = 1;
        return -1;
    }

    eval_err = 1;
    return -1;
}

// COR24 APL Interpreter -- main entry point
// Phase 3.4+: Quad output ([] <- expr) for explicit I/O

#include <stdio.h>
#include "io.h"
#include "num.h"
#include "arr.h"
#include "tok.h"
#include "sym.h"
#include "parse.h"
#include "eval.h"

int main() {
    char line[IO_LINE_MAX];

    arr_reset();
    puts("COR24 APL v0.1");

    while (1) {
        io_print("      ");
        int n = io_getline(line, IO_LINE_MAX);
        if (n == 0) {
            // Empty line -- just re-prompt
        } else {
            int ntok = tokenize(line);
            if (ntok < 0) {
                io_print("  SYNTAX ERROR");
                putchar(10);
            } else {
                // Save heap position for temporary reclamation
                int heap_save = heap_top;

                int root = parse(line);
                if (root < 0) {
                    heap_top = heap_save;
                    io_print("  SYNTAX ERROR");
                    putchar(10);
                } else {
                    eval_err = 0;
                    int result = eval(root);
                    if (eval_err == 2) {
                        heap_top = heap_save;
                        io_print("  VALUE ERROR");
                        putchar(10);
                    } else if (eval_err == 3) {
                        heap_top = heap_save;
                        io_print("  LENGTH ERROR");
                        putchar(10);
                    } else if (eval_err) {
                        heap_top = heap_save;
                        io_print("  DOMAIN ERROR");
                        putchar(10);
                    } else if (node_type[root] == NODE_ASSIGN) {
                        // Assignment: no output (APL convention)
                        // Don't restore heap -- variable value persists
                    } else {
                        // Print result based on rank
                        int rank = arr_rank(result);
                        if (rank == 0) {
                            io_print("  ");
                            print_int(arr_get(result, 0));
                            putchar(10);
                        } else if (rank == 1) {
                            int sz = arr_dim0(result);
                            // Find max width across all elements
                            int maxw = 1;
                            int j = 0;
                            while (j < sz) {
                                int w = num_width(arr_get(result, j));
                                if (w > maxw) maxw = w;
                                j++;
                            }
                            // Print each element right-justified
                            j = 0;
                            while (j < sz) {
                                if (j == 0) putchar(32);
                                print_int_rj(arr_get(result, j), maxw);
                                if (j + 1 < sz) putchar(32);
                                j++;
                            }
                            putchar(10);
                        }
                        // Reclaim temporaries
                        heap_top = heap_save;
                    }
                }
            }
        }
    }
    return 0;
}

